"use strict";rcmail.register_command("add-events-to-calendar",function(){xcalendarMail.showSelectCalendarDialog()});rcmail.addEventListener("beforemenu-open",function(p){if(p.menu==="attachmentmenu"){xcalendarMail.mimeId=p["id"];if($.inArray(p["id"],rcmail.env.xcalendar_mimeIds)!==-1){$("#add-events-to-calendar").show();rcmail.enable_command("add-events-to-calendar",true)}else{$("#add-events-to-calendar").hide()}}});$(document).ready(function(){xcalendarMail.initialize()});var xcalendarMail=new function(){var _this=this;this.mimeId=false;this.initialize=function(){if($("#sidebar-xcalendar").length){_this.getTodaysAgenda();if(rcmail.env.xcalendar_settings.refresh!==0&&Number.isInteger(rcmail.env.xcalendar_settings.refresh)&&rcmail.env.xcalendar_settings.refresh>=5){setInterval(function(){_this.getTodaysAgenda()},rcmail.env.xcalendar_settings.refresh*60*1e3)}}};this.getTodaysAgenda=function(){xframework.ajax("xcalendar.getTodaysAgenda",{},function(response){$("#xcalendar-todays-agenda").removeClass("xspinner").html(response.data)})};this.respond=function(button,response,data){var box=$("#itip-content");var responseText=response.toLowerCase();box.removeClass().addClass("user-status-"+responseText);box.find(".attendees .current-user").removeClass().addClass("current-user attendee-"+responseText);rcmail.http_post("xcalendar.processItipResponse",{data:data,response:response,calendarId:box.find("select").val(),sendReply:box.find(".send-reply").is(":checked")?1:0},rcmail.set_busy(true,"loading"))};this.eventAction=function(action,data){$("#xcalendar-message-itip .header-buttons").hide();rcmail.http_post("xcalendar.processItip"+action,{data:data},rcmail.set_busy(true,"loading"))};this.showResponseControls=function(){$("#itip-content").addClass("show-request-controls")};this.showSelectCalendarDialog=function(){var calendars=rcmail.env.xcalendar_calendars;var select=$("<select id='xcalendar-select-element'>");for(var key in calendars){if(calendars.hasOwnProperty(key)){select.append($("<option>",{value:calendars[key]["id"],text:calendars[key]["name"]}))}}var div=$("<div id='xcalendar-select-dialog'>").append($("<p>").text(rcmail.gettext("select_calendar_for_events","xcalendar"))).append(select);div.dialog({modal:true,resizable:false,closeOnEscape:true,title:rcmail.gettext("select_calendar","xcalendar"),close:function close(){div.dialog("destroy").remove()},buttons:[{text:rcmail.gettext("add_events","xcalendar"),click:function click(){xcalendarMail.addMessageEventsToCalendar($("#xcalendar-select-element").val());$(this).dialog("close")}},{text:rcmail.gettext("cancel"),click:function click(){$(this).dialog("close")}}],width:400})};this.addMessageEventsToCalendar=function(calendarId){rcmail.http_post("xcalendar.addMessageEventsToCalendar",{uid:rcmail.env.uid,mbox:rcmail.env.mailbox,mimeId:_this.mimeId,calendarId:calendarId},rcmail.set_busy(true,"loading"))}};